import { writable } from "svelte/store";
import { Settings } from "./storage";
export const activeWorkspace = writable(null);
export const isLightThemeStore = writable(Settings.isLightTheme);
isLightThemeStore.subscribe(isLightTheme => {
    Settings.isLightTheme = isLightTheme;
    document.documentElement.setAttribute("data-theme", isLightTheme ? "light" : "dark");
});
